mapper.select:
select a.*,
b.bed_no,b.room_id,
c.room_name
from t_live a
inner join t_bed b on a.bed_id = b.id
inner join t_room c on b.room_id = c.id


        and a.user_id = #{userId}


        and a.bed_id = #{bedId}


        and b.room_id = #{roomId}


        and b.bed_no like concat('%',#{bedNo},'%')


order by a.create_time desc
limit #{start},#{limit};

select count(a.id)
from t_live a
inner join t_bed b on a.bed_id = b.id
inner join t_room c on b.room_id = c.id


    and a.user_id = #{userId}


        and a.bed_id = #{bedId}


    and b.room_id = #{roomId}


    and b.bed_no like concat('%',#{bedNo},'%')
